res=0.4
GW=int((maxx-minx)/res)+1; GH=int((maxz-minz)/res)+1
hm=[[None]*GW for _ in range(GH)]
for (X,Y,Z) in pts:
    i=int((X-minx)/res); j=int((Z-minz)/res); cur=hm[j][i]
    if side=='front':
        if cur is None or Y<cur: hm[j][i]=Y
    else:
        if cur is None or Y>cur: hm[j][i]=Y
# plane fit Y=a*X+b*Z+c over grid centers
XX=[];ZZ=[];YY=[]
for j in range(GH):
    for i in range(GW):
        if hm[j][i] is not None:
            XX.append(minx+i*res);ZZ.append(minz+j*res);YY.append(hm[j][i])
n=len(YY)
sx=sum(XX);sz=sum(ZZ);sy=sum(YY)
