theta=math.radians(float(sys.argv[1]))
resx=float(sys.argv[2]); resy=float(sys.argv[3]); thr=float(sys.argv[4])
x=y=z=0.0; active=None; pts=[]
for line in open('/app/text.gcode'):
    s=line.strip()
    if s.startswith('M486'):
        m=re.search(r'S(-?\d+)',s)
        if m: active=int(m.group(1))
        continue
    if not (s.startswith('G0') or s.startswith('G1')): continue
    nx,ny,nz,ne=x,y,z,None
    for p in s.split()[1:]:
        try:
            if p[0]=='X': nx=float(p[1:])
            elif p[0]=='Y': ny=float(p[1:])
            elif p[0]=='Z': nz=float(p[1:])
            elif p[0]=='E': ne=float(p[1:])
        except: pass
    if ne is not None and ne>0 and active==0 and (nx!=x or ny!=y):
        L=math.hypot(nx-x,ny-y); n=max(1,int(L*4))
        for i in range(n+1):
            t=i/n if n else 0
            pts.append((x+(nx-x)*t, y+(ny-y)*t, nz))
    x,y,z=nx,ny,nz
cx=sum(p[0] for p in pts)/len(pts); cy=sum(p[1] for p in pts)/len(pts)
ct=math.cos(theta); st=math.sin(theta)
P=[((X-cx)*ct-(Y-cy)*st,(X-cx)*st+(Y-cy)*ct,Z) for (X,Y,Z) in pts]
xs=[p[0] for p in P]; ys=[p[1] for p in P]
minx,maxx=min(xs),max(xs); miny,maxy=min(ys),max(ys)
GW=int((maxx-minx)/resx)+1; GH=int((maxy-miny)/resy)+1
hm=[[None]*GW for _ in range(GH)]
for (X,Y,Z) in P:
    i=int((X-minx)/resx); j=int((Y-miny)/resy)
    if hm[j][i] is None or Z>hm[j][i]: hm[j][i]=Z
# plane fit (i,j)
XX=[];YY=[];ZZ=[]
for j in range(GH):
    for i in range(GW):
        if hm[j][i] is not None: XX.append(i);YY.append(j);ZZ.append(hm[j][i])
n=len(ZZ); sx=sum(XX);sy=sum(YY);sz=sum(ZZ)
sxx=sum(v*v for v in XX);syy=sum(v*v for v in YY);sxy=sum(XX[k]*YY[k] for k in range(n))
sxz=sum(XX[k]*ZZ[k] for k in range(n));syz=sum(YY[k]*ZZ[k] for k in range(n))
def solve3(M,v):
    M=[r[:] for r in M]; v=v[:]
    for c in range(3):
        piv=max(range(c,3),key=lambda r:abs(M[r][c]))
        M[c],M[piv]=M[piv],M[c]; v[c],v[piv]=v[piv],v[c]; d=M[c][c]
        for r in range(3):
            if r==c: continue
            f=M[r][c]/d
            for k in range(3): M[r][k]-=f*M[c][k]
            v[r]-=f*v[c]
    return [v[i]/M[i][i] for i in range(3)]
a,b,c0=solve3([[sxx,sxy,sx],[sxy,syy,sy],[sx,sy,n]],[sxz,syz,sz])
B=[[0]*GW for _ in range(GH)]
for j in range(GH):
    for i in range(GW):
        if hm[j][i] is not None and hm[j][i]-(a*i+b*j+c0)>thr: B[j][i]=1
# majority denoise
D=[[0]*GW for _ in range(GH)]
for j in range(GH):
    for i in range(GW):
        s=sum(B[jj][ii] for jj in range(max(0,j-1),min(GH,j+2)) for ii in range(max(0,i-1),min(GW,i+2)))
